/**
 * Floor Average Temperature Script
 *
 * Called after collecting all child room telemetry for this floor.
 * msg.data contains temperature from the triggering device.
 * We tag the message with the floor asset ID for downstream saving.
 *
 * Note: Full aggregation requires the 'Aggregate Latest' pattern.
 * This script emits a ready-to-save floor telemetry message.
 */
var temperature = msg.temperature !== undefined ? msg.temperature : null;

if (temperature === null) {
    return null; // discard
}

// The floor asset name is stored in metadata by the relation traversal node
var floorAssetName = metadata.floorAssetName || 'unknown';

// Build floor telemetry payload
msg = {
    avg_temperature: temperature,  // Will be replaced by true avg in aggregation chain
    contributing_room: metadata.deviceName || 'unknown',
    floor_name: floorAssetName,
    ts: new Date().getTime()
};

metadata.targetEntityType = 'ASSET';
metadata.targetEntityName = floorAssetName;

return {msg: msg, metadata: metadata, msgType: msgType};
